using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ─── CalculateTotal: DataRow for inline compile-time constants ───

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00)]    // no tax
    [DataRow(10.00, 2, 0.0, 20.00)]    // multiple quantity, no tax
    [DataRow(10.00, 1, 0.10, 11.00)]   // 10% tax
    [DataRow(25.50, 3, 0.08, 82.62)]   // fractional price + tax
    [DataRow(0.00, 5, 0.20, 0.00)]     // zero price
    [DataRow(99.99, 0, 0.15, 0.00)]    // zero quantity
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice")]
    [DataRow(10.00, -1, 0.10, "quantity")]
    [DataRow(10.00, 1, -0.01, "taxRate")]
    [DataRow(10.00, 1, 1.01, "taxRate")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    // ─── ApplyDiscount: DynamicData for richer/complex scenarios ───

    public static IEnumerable<object[]> ApplyDiscountTestData =>
    [
        [100.00m, 0m, 100.00m],     // no discount
        [100.00m, 10m, 90.00m],     // 10% off
        [100.00m, 50m, 50.00m],     // half off
        [100.00m, 100m, 0.00m],     // full discount
        [49.99m, 25m, 37.4925m],    // fractional result
        [0.00m, 50m, 0.00m],       // zero price
    ];

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    // DynamicData with a method source for invalid-input cases
    public static IEnumerable<object[]> GetInvalidDiscountData()
    {
        yield return [-0.01m];
        yield return [100.01m];
        yield return [-50m];
        yield return [200m];
    }

    [TestMethod]
    [DynamicData(nameof(GetInvalidDiscountData), DynamicDataSourceType.Method)]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(decimal discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, discountPercent));
    }
}

